+fn run_sqlite_busy_lock(path: &Path) -> EngineOutcome {
+    if let Err(err) = initialize_sqlite_db(path) {
+        return EngineOutcome::from_sqlite_error(err);
+    }
+
+    let conn1 = match rusqlite::Connection::open(path) {
